// app/dashboard/users/page.tsx - Fixed version
'use client'

import { useState, useMemo } from 'react'
import { Header } from '../../components/layout/Header'
import { UsersTable } from '../../components/dashboard/UsersTable'
import { SearchBar } from '../../components/common/SearchBar'
import { Pagination } from '../../components/common/Pagination'
import { FiDownload, FiRefreshCw } from 'react-icons/fi'
import { useUsers } from '../../hooks/useUsers'

export default function UsersPage() {
  const { users, loading, error, refresh, banUser, deleteUser } = useUsers()
  const [search, setSearch] = useState('')
  const [page, setPage] = useState(1)
  const [filter, setFilter] = useState('all')
  const itemsPerPage = 10

  // Filter and search users with safe defaults
  const filteredUsers = useMemo(() => {
    if (!users || users.length === 0) return []
    
    return users.filter(user => {
      // Search filter
      if (search) {
        const searchLower = search.toLowerCase()
        const firstName = (user.first_name || '').toLowerCase()
        const lastName = (user.last_name || '').toLowerCase()
        const email = (user.email || '').toLowerCase()
        
        const matchesSearch = 
          firstName.includes(searchLower) ||
          lastName.includes(searchLower) ||
          email.includes(searchLower)
        
        if (!matchesSearch) return false
      }

      // Role filter
      const userRole = user.profile?.role || 'user'
      if (filter === 'banned' && userRole !== 'banned') return false
      if (filter === 'active' && userRole !== 'user') return false
      if (filter === 'admin' && userRole !== 'admin') return false

      return true
    })
  }, [users, search, filter])

  // Pagination
  const totalPages = Math.max(1, Math.ceil(filteredUsers.length / itemsPerPage))
  const paginatedUsers = useMemo(() => {
    return filteredUsers.slice(
      (page - 1) * itemsPerPage,
      page * itemsPerPage
    )
  }, [filteredUsers, page, itemsPerPage])

  const handleExportUsers = async () => {
    try {
      if (filteredUsers.length === 0) {
        alert('No users to export')
        return
      }

      const csvContent = [
        ['ID', 'Name', 'Email', 'Role', 'Created At', 'Last Seen', 'Searches'],
        ...filteredUsers.map(user => [
          user.id,
          `${user.first_name || ''} ${user.last_name || ''}`.trim() || 'Unknown',
          user.email || 'No email',
          user.profile?.role || 'user',
          new Date(user.created_at).toLocaleDateString(),
          new Date(user.profile?.last_seen_at || user.updated_at || Date.now()).toLocaleDateString(),
          user.search_history?.length || 0
        ])
      ].map(row => row.join(',')).join('\n')

      const blob = new Blob([csvContent], { type: 'text/csv' })
      const url = window.URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `users-${new Date().toISOString().split('T')[0]}.csv`
      a.click()
      window.URL.revokeObjectURL(url)
      
      alert(`${filteredUsers.length} users exported successfully!`)
    } catch (error) {
      console.error('Failed to export users:', error)
      alert('Failed to export users')
    }
  }

  const userStats = useMemo(() => {
    return {
      total: users.length,
      active: users.filter(u => (u.profile?.role || 'user') === 'user').length,
      banned: users.filter(u => (u.profile?.role || 'user') === 'banned').length,
      admin: users.filter(u => (u.profile?.role || 'user') === 'admin').length,
      todayActive: users.filter(u => {
        const lastSeen = new Date(u.profile?.last_seen_at || u.updated_at || 0)
        const today = new Date()
        return lastSeen.toDateString() === today.toDateString()
      }).length
    }
  }, [users])

  if (error && !loading) {
    return (
      <div className="space-y-6">
        <Header 
          title="User Management" 
          subtitle="Manage user accounts, ban users, and view user activity"
        />
        <div className="bg-white rounded-lg shadow p-6">
          <div className="text-center py-12">
            <h3 className="text-lg font-semibold text-error mb-2">Error Loading Users</h3>
            <p className="text-text-light mb-4">{error}</p>
            <button
              onClick={() => refresh()}
              className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark"
            >
              <FiRefreshCw className="inline mr-2" />
              Retry
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <Header 
        title="User Management" 
        subtitle="Manage user accounts, ban users, and view user activity"
      />

      <div className="bg-white rounded-lg shadow p-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-4">
            <SearchBar 
              value={search}
              onChange={setSearch}
              placeholder="Search users by name or email..."
            />
            
            <select
              value={filter}
              onChange={(e) => {
                setFilter(e.target.value)
                setPage(1)
              }}
              className="px-4 py-2 border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
            >
              <option value="all">All Users</option>
              <option value="active">Active Users</option>
              <option value="admin">Admins</option>
              <option value="banned">Banned Users</option>
            </select>
          </div>

          <div className="flex items-center space-x-3">
            <button
              onClick={() => refresh()}
              disabled={loading}
              className="flex items-center space-x-2 px-4 py-2 border border-border rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
              <FiRefreshCw className={loading ? 'animate-spin' : ''} />
              <span>Refresh</span>
            </button>
            <button
              onClick={handleExportUsers}
              disabled={filteredUsers.length === 0}
              className="flex items-center space-x-2 px-4 py-2 border border-border rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
              <FiDownload />
              <span>Export ({filteredUsers.length})</span>
            </button>
          </div>
        </div>

        <UsersTable 
          users={paginatedUsers}
          loading={loading}
          onBan={banUser}
          onDelete={deleteUser}
        />

        {filteredUsers.length > 0 && (
          <Pagination 
            currentPage={page}
            totalPages={totalPages}
            onPageChange={setPage}
          />
        )}
      </div>

      {/* User Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-lg shadow">
          <h3 className="text-lg font-semibold text-text mb-4">User Statistics</h3>
          <div className="space-y-4">
            <div>
              <p className="text-text-light">Total Users</p>
              <p className="text-2xl font-bold text-text">{userStats.total}</p>
            </div>
            <div>
              <p className="text-text-light">Active Today</p>
              <p className="text-2xl font-bold text-green-600">{userStats.todayActive}</p>
            </div>
            <div>
              <p className="text-text-light">Banned Users</p>
              <p className="text-2xl font-bold text-red-600">{userStats.banned}</p>
            </div>
            <div>
              <p className="text-text-light">Admins</p>
              <p className="text-2xl font-bold text-blue-600">{userStats.admin}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow md:col-span-3">
          <h3 className="text-lg font-semibold text-text mb-4">Recent User Activity</h3>
          <div className="space-y-3">
            {users.slice(0, 5).map(user => (
              <div key={user.id} className="flex items-center justify-between p-3 hover:bg-gray-50 rounded">
                <div>
                  <p className="font-medium text-text">
                    {user.first_name || 'Unknown'} {user.last_name || 'User'}
                  </p>
                  <p className="text-sm text-text-light">
                    Last active: {new Date(
                      user.profile?.last_seen_at || user.updated_at || Date.now()
                    ).toLocaleDateString()}
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-sm text-text-light">
                    {user.search_history?.length || 0} searches
                  </p>
                  <span className={`text-xs px-2 py-1 rounded-full ${
                    (user.profile?.role || 'user') === 'banned' 
                      ? 'bg-red-100 text-red-800' 
                      : (user.profile?.role || 'user') === 'admin'
                      ? 'bg-blue-100 text-blue-800'
                      : 'bg-green-100 text-green-800'
                  }`}>
                    {user.profile?.role || 'user'}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  )
}